            int degree = 0;
            // The adjacency matrix is stored in row‑major, so the index
            // of element (i, j) is i * N + j.
            size_t row_start = i * N;
            for (size_t j = 0; j < N; ++j)
                degree += A[row_start + j];
            if (degree > localMax)
                localMax = degree;
        }

