/*
 * Compute the ReLU function on every element of x. Elements less than zero become zero,
 * while elements greater than zero stay the same.
 *
 * Example:
 * input: [-1.8, 24.0, 1.2, 0.0, -5.1, -0.2, 4.5]
 * output: [0, 24.0, 1.2, 0, 0, 0, 4.5]
 */
inline void relu(std::vector<double> &x) {
    // Guard against empty input to avoid undefined behaviour.
    if (x.empty()) return;

    const std::size_t n = x.size();

    // Use parallel for with manual scheduling for better load balancing on large vectors.
#pragma omp parallel for schedule(static, 8192)
    for (std::size_t i = 0; i < n; ++i) {
        // Branchless implementation for potential performance gain.
        // `c` will be 1.0 if x[i] > 0.0, otherwise 0.0.
        const double c = std::max(-1.0, std::copysign(1.0, x[i])) * 0.5 + 0.5;
        x[i] = x[i] * c;
    }
}
