struct COOElement {
    size_t row, column;
    double value;
};

/* Compute y = alpha*A*x + beta*y where alpha and beta are scalars, x and y are vectors,
 * and A is a sparse matrix stored in COO format.
 * x and y are length N and A is M x N.
 * Example:
 * input: alpha=0.5 beta=1.0 A=[{0,1,3}, {1,0,-1}] x=[-4, 2] y=[-1,1]
 * output: y=[2, 3]
 */
void spmv(double alpha,
          const std::vector<COOElement> &A,
          const std::vector<double> &x,
          double beta,
          std::vector<double> &y,
          size_t M, size_t N) {

    // Scale y by beta in parallel
    #pragma omp parallel for schedule(static)
    for (ptrdiff_t i = 0; i < static_cast<ptrdiff_t>(y.size()); ++i) {
        y[i] *= beta;
    }

    // Accumulate contributions; parallelize with atomic to preserve correctness
    #pragma omp parallel for schedule(static, 8192)
    for (ptrdiff_t idx = 0; idx < static_cast<ptrdiff_t>(A.size()); ++idx) {
        const auto &e = A[idx];
        // Bounds are still checked to preserve original behavior
        if (e.row < M && e.column < N) {
            double val = alpha * e.value * x[e.column];
            #pragma omp atomic
            y[e.row] += val;
        }
    }
}
