#pragma once
#include <vector>
#include <algorithm>

/* Union‑Find (Disjoint Set Union) structure */
struct DSU {
    std::vector<int> parent, rank;
    DSU(int n) : parent(n), rank(n, 0) { std::iota(parent.begin(), parent.end(), 0); }

    int find(int v) {
        while (parent[v] != v) v = parent[v];
        return v;
    }

    void unite(int a, int b) {
        int pa = find(a), pb = find(b);
        if (pa == pb) return;
        if (rank[pa] < rank[pb]) parent[pa] = pb;
        else if (rank[pb] < rank[pa]) parent[pb] = pa;
        else { parent[pb] = pa; ++rank[pa]; }
    }
};

/* Count the number of connected components in the undirected graph
 * defined by the adjacency matrix A (row‑major, NxN).
 */
int componentCount(std::vector<int> const& A, size_t N) {
    DSU dsu(N);
    // Each edge appears twice in the symmetric matrix; process upper triangle only.
    for (size_t i = 0; i < N; ++i) {
        for (size_t j = i + 1; j < N; ++j) {
            if (A[i * N + j] == 1)
                dsu.unite(static_cast<int>(i), static_cast<int>(j));
        }
    }
    // Count distinct roots.
    int comp = 0;
    for (size_t i = 0; i < N; ++i) {
        if (dsu.find(static_cast<int>(i)) == static_cast<int>(i))
            ++comp;
    }
    return comp;
}
