    std::fill(bins.begin(), bins.end(), 0);

    // Local per-thread counters to avoid data races
    const int teamSize = omp_get_max_threads();
    std::vector<std::array<std::size_t, 4>> localBins(teamSize);
    #pragma omp parallel
    {
        int threadIdx = omp_get_thread_num();
        auto &local = localBins[threadIdx];
        std::fill(local.begin(), local.end(), 0);

        // Divide work among teams; OpenMP handles scheduling
        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < points.size(); ++i) {
            const Point &p = points[i];
            // Straightforward quadrant detection with minimal branching
            if (p.x >= 0) {
                local[p.y >= 0 ? 0 : 3] += 1;
            } else {
                local[p.y >= 0 ? 1 : 2] += 1;
            }
        }
    }

    // Merge per-thread results into the final bins
    for (const auto &local : localBins) {
        for (std::size_t q = 0; q < 4; ++q) {
            bins[q] += local[q];
        }
    }
}
