```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <limits>

/*
 * Fastest BFS for an undirected, connected graph given as a row‑major adjacency
 * matrix A (size N×N).  For each vertex we store only the minimal distance from
 * the source.  The algorithm uses a hand‑rolled circular queue and
 * pre‑allocated memory so that no heap operations occur during traversal.
 */
static inline int shortestPathLength(std::vector<int> const& A,
                                      size_t const N,
                                      int const source,
                                      int const dest) noexcept
{
    // visited array can be a simple byte per vertex
    std::vector<unsigned char> visited(N, 0);
    // queue stores vertex indices; size N is enough for a simple BFS
    std::vector<int> q(N);
    // array of depths parallel to q (can be omitted by storing distance in visited)
    std::vector<int> depth(N);

    int head = 0, tail = 0;

    visited[source] = 1;
    q[tail] = source;
    depth[tail] = 0;
    ++tail;

    while (head != tail) {
        const int v   = q[head];
        const int d   = depth[head];
        head = (head + 1) % N;          // pop

        if (v == dest) return d;

        // adjacency: row v in the matrix starts at v * N
        const int* row = A.data() + v * N;
        for (int i = 0; i < static_cast<int>(N); ++i) {
            if (row[i] && !visited[i]) {
                visited[i] = 1;
                q[tail]    = i;
                depth[tail] = d + 1;
                tail = (tail + 1) % N;
            }
        }
    }

    return std::numeric_limits<int>::max();  // unreachable (should not happen)
}
