#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/* Optimised sparse‑dense multiplication Y = A · X.
 * A : M×K sparse matrix in COO format
 * X : K×N sparse matrix in COO format
 * Y : dense M×N result matrix, row‑major
 *
 * The implementation groups the entries of X by row so that
 * each A‑element only scans the relevant X‑entries.  The outer
 * loop over A is embarrassingly parallel and uses OpenMP.
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double>& Y,
          size_t M, size_t K, size_t N)
{
    // allocate result matrix
    Y.assign(M * N, 0.0);

    /* Build a map from X.row → list of (column, value) pairs.
     * The map is built once and can be used for all A‑entries.
     */
    std::unordered_map<size_t, std::vector<std::pair<size_t,double>>> x_by_row;
    x_by_row.reserve(X.size());
    for (auto const &e : X) {
        x_by_row[e.row].emplace_back(e.column, e.value);
    }

#pragma omp parallel for schedule(dynamic, 1024)
    for (size_t ai = 0; ai < A.size(); ++ai) {
        const auto &a = A[ai];
        // find all X entries whose row equals a.column
        auto it = x_by_row.find(a.column);
        if (it == x_by_row.end()) continue;
        const auto &vec = it->second;
        double const aval = a.value;
        size_t const arow = a.row;
        size_t const rowOffset = arow * N;
        for (auto const &p : vec) {
            Y[rowOffset + p.first] += aval * p.second;
        }
    }
}
