struct Element {
    std::size_t index;
    double       value;
};

/* Compute z = alpha*x + y where x and y are sparse vectors.
 * The result is stored in a dense vector z.
 *
 * The function is thread‑safe and parallelised using OpenMP.
 * The order of updates to individual indices does not matter
 * because all operations are additions and commutative.
 */
void sparseAxpy(double alpha,
                const std::vector<Element> &x,
                const std::vector<Element> &y,
                std::vector<double> &z)
{
    // ------------------------------------------------------------------
    //  1) Add the contribution from the vector x
    // ------------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i) {
        std::size_t idx = x[i].index;
        double v = alpha * x[i].value;
        #pragma omp atomic
        z[idx] += v;
    }

    // ------------------------------------------------------------------
    //  2) Add the contribution from the vector y
    // ------------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y.size(); ++i) {
        std::size_t idx = y[i].index;
        double v = y[i].value;
        #pragma omp atomic
        z[idx] += v;
