#pragma once
#include <vector>
#include <limits>
#include <algorithm>

/* Find the size of the largest connected component in an undirected graph
 * represented by an NxN adjacency matrix.
 * A is a row‑major vector of size N*N.
 */
int largestComponent(const std::vector<int> &A, size_t N)
{
    // Union–Find (Disjoint Set Union) implementation
    struct DSU {
        std::vector<int> parent, sz;
        DSU(size_t n) : parent(n), sz(n, 1) {
            for (size_t i = 0; i < n; ++i) parent[i] = i;
        }
        int find(int x) {
            int p = parent[x];
            if (p != x) parent[x] = find(p);
            return parent[x];
        }
        void unite(int a, int b) {
            a = find(a); b = find(b);
            if (a == b) return;
            if (sz[a] < sz[b]) std::swap(a, b);
            parent[b] = a;
            sz[a] += sz[b];
        }
        int compSize(int x) { return sz[find(x)]; }
    };

    DSU dsu(N);

    // Iterate over upper triangle to avoid duplicate edges
    for (size_t i = 0; i < N; ++i) {
        size_t row_offset = i * N;
        for (size_t j = i + 1; j < N; ++j) {
            if (A[row_offset + j] == 1) {
                dsu.unite(static_cast<int>(i), static_cast<int>(j));
            }
        }
    }

    int maxSize = 0;
    for (size_t i = 0; i < N; ++i) {
        if (dsu.parent[i] == static_cast<int>(i)) {          // root
            int sz = dsu.sz[i];
            if (sz > maxSize) maxSize = sz;
        }
    }
    return maxSize;
}
