/* Return the distance between the closest two elements in the vector x.
   Example:
   input: [7, 3, 9, 12, 31, 1]
   output: 2
*/
double closestPair(std::vector<double> const& x) {
    // The vector needs to have at least two elements
    if (x.size() < 2) {
        return 0.0;
    }

    const std::size_t n = x.size();
    double minDist = std::numeric_limits<double>::max();

    #pragma omp parallel
    {
        // Each thread keeps a local minimum to avoid false sharing
        double localMin = std::numeric_limits<double>::max();

        #pragma omp for nowait
        for (std::size_t i = 0; i < n - 1; ++i) {
            for (std::size_t j = i + 1; j < n; ++j) {
                double dist = std::abs(x[i] - x[j]);
                if (dist < localMin) {
                    localMin = dist;
                }
            }
        }

        // Reduce local minima into the global one
        #pragma omp critical
        if (localMin < minDist) {
            minDist = localMin;
        }
    }

    return minDist;
}
