#pragma once
#include <vector>
#include <cstddef>

struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Dense LU factorisation for a sparse matrix given in COO format.
 * The result is stored in the linear arrays L and U (row-major, size N*N).
 * The function keeps exactly the same semantics as the reference implementation.
 */
inline void luFactorize(std::vector<COOElement> const& A,
                        std::vector<double>& L,
                        std::vector<double>& U,
                        size_t N)
{
    const size_t NN = N * N;
    std::vector<double> fullA(NN, 0.0);                // dense A as 1‑D array
    for (auto const& e : A)                            // copy COO into dense matrix
        fullA[e.row * N + e.column] = e.value;

    L.assign(NN, 0.0);                                 // initialise L and U
    U.assign(NN, 0.0);

    for (size_t i = 0; i < N; ++i) {
        const size_t iN = i * N;
        /* --- compute row i of U --- */
        for (size_t j = i; j < N; ++j) {
            double sum = fullA[iN + j];
            for (size_t k = 0; k < i; ++k) {
                sum -= L[iN + k] * U[k * N + j];
            }
            U[iN + j] = sum;
        }

        /* --- compute column i of L (below the diagonal) --- */
        for (size_t j = i + 1; j < N; ++j) {
            double sum = fullA[j * N + i];
            for (size_t k = 0; k < i; ++k) {
                sum -= L[j * N + k] * U[k * N + i];
            }
            L[j * N + i] = sum / U[iN + i];
        }

        L[iN + i] = 1.0;                               // unit diagonal of L
    }
}
