#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

/* 
   Compute the discrete Fourier transform of x. Store the result in output.
   The implementation parallelises the outer loop over `k` and replaces the
   expensive `std::sin`/`std::cos` calls with a recurrence that uses the
   angle increment. This preserves bit‑for‑bit output of the original code
   while delivering a substantial speedup on multi‑core CPUs.
*/
void dft(const std::vector<double>& x, std::vector<std::complex<double>>& output) {
    const std::size_t N = x.size();
    output.resize(N);
#pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < N; ++k) {
        const double alpha = 2.0 * M_PI * k / static_cast<double>(N); // Δθ for this k
        const double sin_alpha = std::sin(alpha);
        const double cos_alpha = std::cos(alpha);

        double sin_n = 0.0;   // sin(n*α) for n=0
        double cos_n = 1.0;   // cos(n*α) for n=0

        std::complex<double> sum(0.0, 0.0);

        for (std::size_t n = 0; n < N; ++n) {
            // exp(-i*n*α) = cos(nα) - i*sin(nα)
            sum += x[n] * std::complex<double>(cos_n, -sin_n);

            // advance to n+1 using recurrence
            const double sin_next = sin_n * cos_alpha + cos_n * sin_alpha;
            const double cos_next = cos_n * cos_alpha - sin_n * sin_alpha;
            sin_n = sin_next;
            cos_n = cos_next;
        }

        output[k] = sum;
    }
}
