inline void axpy(double alpha,
                 std::vector<double> const& x,
                 std::vector<double> const& y,
                 std::vector<double> &z) {
    const size_t n = x.size();
    // Ensure that all operands have the same length
    if (y.size() != n || z.size() != n) {
        // In production code you would throw an exception or handle this case.
        // For the purpose of this exercise we simply return.
        return;
    }

    // OpenMP parallel loop with SIMD hint for the compiler.
    #pragma omp parallel for schedule(static, 128) SIMD
    for (ptrdiff_t i = 0; i < static_cast<ptrdiff_t>(n); ++i) {
        z[i] = alpha * x[i] + y[i];
    }
