/**
 * @brief Computes one iteration of a 3‑point 1‑D Jacobi stencil.
 * @param input  The source vector (read‑only).
 * @param output The destination vector (writable, must be the same size as `input`).
 *
 * Each output element is the average of the corresponding input element
 * and its two immediate neighbors. Out‑of‑range neighbors are treated as 0.
 *
 * The implementation is heavily vectorised and parallelised with OpenMP.
 */
inline void jacobi1D(std::vector<double> const& input, std::vector<double> &output)
{
    const std::size_t n = input.size();
    if (n == 0) return;

    // Pre‑compute constant 1/3
    constexpr double inv3 = 1.0 / 3.0;

    // Avoid redundant bounds check on each iteration
    const double *restrict src = input.data();
    double *restrict dst = output.data();

#ifdef _OPENMP
    const int nth = omp_get_max_threads();
    // Static schedule gives good cache locality
    #pragma omp parallel for schedule(static) num_threads(nth)
#endif
    for (std::size_t i = 0; i < n; ++i) {
        double left  = (i > 0)       ? src[i - 1] : 0.0;
        double middle = src[i];
        double right = (i + 1 < n)  ? src[i + 1] : 0.0;

        dst[i] = (left + middle + right) * inv3;
    }
}
