/* Find the k‑th smallest element of the vector x.
   The function returns the same result as sorting the entire vector
   and picking the (k‑1)th element, but in O(n) expected time.
   The original input vector is not modified.
*/
int findKthSmallest(std::vector<int> const& x, int k) {
    // Make a copy to avoid modifying the original vector
    std::vector<int> copy = x;

    // nth_element partially sorts such that the element at the
    // (k-1)th position is the element that would be there in
    // a fully sorted array. All elements before it are <= it,
    // all after are >= it.
    std::nth_element(copy.begin(),
                     copy.begin() + (k - 1),
                     copy.end());

    return copy[k - 1];
}
