#pragma once
#include <vector>
#include <limits>
#include <cmath>
#include <cstddef>
#include <algorithm>
#include <omp.h>

struct Point
{
    double x, y;
};

/// @brief  Compute the area of a triangle defined by three points.
/// @details Implemented inline in the same translation unit to avoid
///          function-call overhead in the triple nested loops.
static inline double triangle_area(const Point& A,
                                   const Point& B,
                                   const Point& C)
{
    // Using the shoelace formula: 0.5 * | (x1(y2‑y3) + x2(y3‑y1) + x3(y1‑y2)) |
    return 0.5 * std::abs(
        A.x * (B.y - C.y) +
        B.x * (C.y - A.y) +
        C.x * (A.y - B.y));
}

/// @brief  Return the area of the smallest triangle that can be formed by any 3 points.
double smallestArea(const std::vector<Point>& points)
{
    const std::size_t n = points.size();
    if (n < 3)
        return 0.0;

    // `minArea` is shared across the OpenMP region.
    double minArea = std::numeric_limits<double>::infinity();

    // The triple nested loops are parallelised using OpenMP.
    // `omp parallel for collapse(3)` gives the outermost two loops a combined schedule
    // which distributes the work evenly across the 8 available threads.
    #pragma omp parallel for collapse(3) schedule(static)
    for (std::size_t i = 0; i < n - 2; ++i) {
        for (std::size_t j = i + 1; j < n - 1; ++j) {
            for (std::size_t k = j + 1; k < n; ++k) {
                const double area = triangle_area(points[i], points[j], points[k]);

                // Critical section is avoided by each thread maintaining a local minimum
                // and updating the shared minimum only when a new global minimum is found.
                #pragma omp atomic min
                minArea = std::min(minArea, area);
            }
        }
    }

    return minArea;
}
