#pragma once
#include <vector>
#include <algorithm>
#include <limits>
#include <omp.h>

/*
   Replace the i‑th element of the vector x with the minimum value from
   indices 0 through i.
   Example:
      input : [8, 6, -1, 7, 3, 4, 4]
      output: [8, 6, -1, -1, -1, -1, -1]
*/
inline void partialMinimums(std::vector<float> &x)
{
    const std::size_t n = x.size();
    if (n == 0) return;

    /* If the vector is very small we fall back on a sequential
       implementation – the overhead of threading would dominate. */
    const std::size_t small_threshold = 64;
    if (n <= small_threshold) {
        float cur_min = std::numeric_limits<float>::max();
        for (std::size_t i = 0; i < n; ++i) {
            cur_min = std::min(cur_min, x[i]);
            x[i] = cur_min;
        }
        return;
    }

    const int nthreads = omp_get_max_threads();
    std::vector<float> block_pre_min(nthreads);   // prefix minima of each block
    std::vector<float> block_local_min(nthreads); // local minimum per block
    const std::size_t block_size = (n + nthreads - 1) / nthreads;

    /* First pass – compute the local minima of each block in parallel. */
#pragma omp parallel for schedule(static, 1)
    for (int t = 0; t < nthreads; ++t) {
        const std::size_t start = t * block_size;
        const std::size_t end   = std::min(start + block_size, n);
        if (start >= end) {
            block_local_min[t] = std::numeric_limits<float>::max();
            continue;
        }
        float min_val = std::numeric_limits<float>::max();
        for (std::size_t i = start; i < end; ++i) {
            if (x[i] < min_val) min_val = x[i];
        }
        block_local_min[t] = min_val;
    }

    /* Second pass – prefix scan of block minima (sequential is cheap). */
    float acc = std::numeric_limits<float>::max();
    for (int t = 0; t < nthreads; ++t) {
        acc = std::min(acc, block_local_min[t]);
        block_pre_min[t] = acc;
    }

    /* Third pass – apply the prefix result to each element of the block. */
#pragma omp parallel for schedule(static, 1)
    for (int t = 0; t < nthreads; ++t) {
        const std::size_t start = t * block_size;
        const std::size_t end   = std::min(start + block_size, n);
        if (start >= end) continue;

        /* The first element of the block must be min(previous blocks, itself). */
        float cur_min = block_pre_min[t];
        for (std::size_t i = start; i < end; ++i) {
            if (x[i] < cur_min) cur_min = x[i];
            x[i] = cur_min;
        }
    }
}
