#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Set every cell's value to 1 if it has exactly one neighbor that's a 1.
   Otherwise set it to 0.  Neighbors are the cells directly above, below,
   to the left, and to the right.  Diagonal cells are ignored.  The
   routine works on N×N integer grids stored in row-major order.
*/
inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int>& output,
                     size_t N) noexcept
{
    // Avoid negative indices when N == 0
    if (N == 0) return;

    // Pointers to the underlying data for faster indexing
    int const* const in  = input.data();
    int*       const out = output.data();

    const size_t stride = N;

    // Parallelise the outer loop; each thread works on a different row
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        const size_t rowOffset = i * stride;
        const size_t rowAbove  = (i == 0)     ? static_cast<size_t>(-1) : rowOffset - stride;
        const size_t rowBelow  = (i == N-1)   ? static_cast<size_t>(-1) : rowOffset + stride;

        for (size_t j = 0; j < N; ++j)
        {
            int count = 0;

            // Above
            if (rowAbove != static_cast<size_t>(-1) && in[rowAbove + j] == 1)
                ++count;

            // Below
            if (rowBelow != static_cast<size_t>(-1) && in[rowBelow + j] == 1)
                ++count;

            // Left
            if (j > 0 && in[rowOffset + j - 1] == 1)
                ++count;

            // Right
            if (j + 1 < N && in[rowOffset + j + 1] == 1)
                ++count;

            out[rowOffset + j] = (count == 1) ? 1 : 0;
        }
    }
}
