inline size_t findClosestToPi(const std::vector<double>& x) {
    const size_t n = x.size();
    if (n == 0) return static_cast<size_t>(-1);   // handle empty vector

    // Single‑thread seed for the best index and distance
    size_t best_idx = 0;
    double best_dist = std::abs(x[0] - M_PI);

    // Use OpenMP block‑structured parallel-for with a reduction
    #pragma omp parallel
    {
        size_t thread_best_idx = best_idx;
        double thread_best_dist = best_dist;

        #pragma omp for schedule(static)
        for (size_t i = 1; i < n; ++i) {
            const double d = std::abs(x[i] - M_PI);
            if (d < thread_best_dist) {
                thread_best_dist = d;
                thread_best_idx = i;
            }
        }

        // Reduce the thread local best to the global best
        #pragma omp critical
        {
            if (thread_best_dist < best_dist) {
                best_dist = thread_best_dist;
                best_idx = thread_best_idx;
            }
        }
