#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>

struct Point {
    double x, y;
};

/* Return the convex hull of the given set of points in counter‑clockwise order
 * (starting at the point with the smallest x, breaking ties with the smallest y).
 * The original algorithm is Andrew's monotone chain – O(N log N).
 */
inline double cross(const Point& a, const Point& b, const Point& c) {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

void convexHull(const std::vector<Point>& points, std::vector<Point>& hull) {
    const std::size_t n = points.size();
    if (n < 3) {                // trivial case
        hull = points;
        return;
    }

    // Sort points lexicographically by x, then y
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    hull.clear();
    hull.reserve(n);                 // maximum size will never exceed n

    // Build lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], sorted[i]) <= 0) {
            hull.pop_back();
        }
        hull.push_back(sorted[i]);
    }

    // Build upper hull
    std::size_t lower_size = hull.size();
    for (std::size_t i = n - 1; i > 0; --i) {   // stop when i == 0
        while (hull.size() > lower_size &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], sorted[i - 1]) <= 0) {
            hull.pop_back();
        }
        hull.push_back(sorted[i - 1]);
    }

    // Remove duplicated last point
    hull.pop_back();
}
