#include <omp.h>

/**
 * Perform one Jacobi iteration on a 2‑D NxN grid.
 *
 * The algorithm uses a 5‑point stencil with zero‑pad boundary handling.
 * OpenMP parallelism and pointer arithmetic are employed to maximise
 * throughput on a modern x86‑64 machine with 8 cores and GCC‑8+/9+.
 *
 * @param input   Read‑only reference to the input grid (row‑major).
 * @param output  Reference to the output grid (row‑major).  Caller must
 *                allocate a buffer of size N*N.
 * @param N       Size of the grid (N×N).
 */
inline void jacobi2D(std::vector<double> const& input,
                     std::vector<double> &output,
                     std::size_t N)
{
    // Cast to raw pointers for fastest access
    const double* restrict in  = input.data();
    double*       restrict out = output.data();

    const std::size_t stride = N;               // columns per row
    const double inv5 = 0.2;                    // 1/5.0

    // Parallel over all rows; the threads will execute contiguous blocks
    // which gives good cache locality.  The outer loop is hidden from
    // the compiler by an OpenMP schedule(static) hint.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t iTop    = (i > 0)     ? (i - 1) * stride : 0;
        const std::size_t iBottom = (i < N-1)   ? (i + 1) * stride : 0;
        const std::size_t iCurr   = i * stride;

        for (std::size_t j = 0; j < N; ++j) {
            double sum = in[iCurr + j];        // center

            // Add north and south neighbours if not on boundary
            if (i > 0)     sum += in[iTop    + j];
            if (i < N-1)   sum += in[iBottom + j];

            // Add west neighbour if not on first column
            if (j > 0)     sum += in[iCurr + j - 1];
            // Add east neighbour if not on last column
            if (j < N-1)   sum += in[iCurr + j + 1];

            out[iCurr + j] = sum * inv5;
        }
    }
}
