    std::sort(indices.begin(), indices.end(),
              [&x](size_t i1, size_t i2) { return x[i1] < x[i2]; });

    // Store the rank for each original position
    for (size_t i = 0; i < indices.size(); ++i) {
        ranks_[indices[i]] = i;
    }
