#pragma once
#include <numeric>
#include <vector>
#include <cstddef>
#ifdef _OPENMP
#include <omp.h>
#endif

/* Compute the prefix sum of the vector x into output.
   The algorithm uses a 2‑stage parallel prefix (per‑thread local scan,
   followed by a sequential accumulation of block sums and a final
   offset addition).  The behavior (output order, inclusive scan) is
   identical to the standard library implementation. */
void prefixSum(const std::vector<int64_t>& x, std::vector<int64_t>& output) {
    std::size_t n = x.size();
    output.resize(n);
    if (n == 0) return;

    std::vector<int64_t> temp(n);
    std::size_t threads = 1;
#ifdef _OPENMP
    threads = omp_get_max_threads();
#endif
    std::vector<int64_t> blockSums(threads, 0);

    // Stage 1: per‑thread inclusive scan
#pragma omp parallel
    {
        std::size_t tid = 0;
#ifdef _OPENMP
        tid = omp_get_thread_num();
#endif
        std::size_t blockSize = (n + threads - 1) / threads;
        std::size_t start = tid * blockSize;
        std::size_t end   = std::min(start + blockSize, n);

        int64_t sum = 0;
        for (std::size_t i = start; i < end; ++i) {
            sum += x[i];
            temp[i] = sum;
        }
        blockSums[tid] = sum;
    }

    // Stage 2: accumulate block sums sequentially
    int64_t offset = 0;
    for (std::size_t i = 0; i < threads; ++i) {
        int64_t old = blockSums[i];
        blockSums[i] = offset;
        offset += old;
    }

    // Stage 3: add block offsets to the per‑thread results
#pragma omp parallel
    {
        std::size_t tid = 0;
#ifdef _OPENMP
        tid = omp_get_thread_num();
#endif
        std::size_t blockSize = (n + threads - 1) / threads;
        std::size_t start = tid * blockSize;
        std::size_t end   = std::min(start + blockSize, n);
        int64_t add = blockSums[tid];

        for (std::size_t i = start; i < end; ++i) {
            output[i] = temp[i] + add;
        }
    }
}
