#include <omp.h>

#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

inline void fft_inplace(std::vector<std::complex<double>>& a) {
    const size_t N = a.size();
    if (N <= 1) return;

    // Bit-reversal permutation
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        size_t j = i;
        // reverse bits of j
        j = ((j & 0xaaaaaaaaU) >> 1) | ((j & 0x55555555U) << 1);
        j = ((j & 0xccccccccU) >> 2) | ((j & 0x33333333U) << 2);
        j = ((j & 0xf0f0f0f0U) >> 4) | ((j & 0x0f0f0f0fU) << 4);
        j = ((j & 0xff00ff00U) >> 8) | ((j & 0x00ff00ffU) << 8);
        j = ((j >> 16) | (j << 16)) >> (32 - (size_t)std::log2(N));
        if (j > i) std::swap(a[i], a[j]);
    }

    // Cooley–Tukey FFT
    for (size_t len = 2; len <= N; len <<= 1) {
        double angle = -2.0 * M_PI / len;
        std::complex<double> wlen(std::cos(angle), std::sin(angle));

        #pragma omp parallel for schedule(static)
        for (size_t i = 0; i < N; i += len) {
            std::complex<double> w(1.0, 0.0);
            for (size_t j = 0; j < len / 2; ++j) {
                std::complex<double> u = a[i + j];
                std::complex<double> v = a[i + j + len/2] * w;
                a[i + j] = u + v;
                a[i + j + len/2] = u - v;
                w *= wlen;
            }
        }
    }
}

inline void ifft(std::vector<std::complex<double>>& a) {
    const size_t N = a.size();
    // Conjugate
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
        a[i] = std::conj(a[i]);

    // Forward FFT
    fft_inplace(a);

    // Conjugate again
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
        a[i] = std::conj(a[i]);

    // Scale
    const double invN = 1.0 / static_cast<double>(N);
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
        a[i] *= invN;
}
