#pragma once
#include <vector>
#include <algorithm>
#include <limits>
#include <cmath>
#include <omp.h>

struct Point
{
    double x, y;
};

inline double dist2(const Point &a, const Point &b)
{
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return dx * dx + dy * dy;
}

double closestPair(std::vector<Point> const &points)
{
    const size_t n = points.size();
    if (n < 2) return 0.0;

    // Work on a copy sorted by x
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(),
              [](const Point &a, const Point &b) { return a.x < b.x; });

    std::vector<Point> buf(n);
    const auto rec = [&](auto self, int l, int r) -> double
    {
        int const len = r - l;
        if (len <= 3) {
            double d2 = std::numeric_limits<double>::max();
            for (int i = l; i < r; ++i)
                for (int j = i + 1; j < r; ++j)
                    d2 = std::min(d2, dist2(pts[i], pts[j]));
            std::sort(pts.begin() + l, pts.begin() + r,
                      [](const Point &a, const Point &b) { return a.y < b.y; });
            return d2;
        }
        int const m = (l + r) >> 1;
        double midx = pts[m].x;

        // Parallel divide & conquer
        double dl, dr;
#pragma omp task shared(dl) if(len > 64)
        dl = self(self, l, m);
#pragma omp task shared(dr) if(len > 64)
        dr = self(self, m, r);
#pragma omp taskwait

        double d2 = std::min(dl, dr);

        // Merge step: y‑sorted
        std::inplace_merge(pts.begin() + l, pts.begin() + m, pts.begin() + r,
                           [](const Point &a, const Point &b) { return a.y < b.y; });

        // Build strip
        std::vector<Point> strip;
        for (int i = l; i < r; ++i) {
            if (std::fabs(pts[i].x - midx) < std::sqrt(d2))
                strip.push_back(pts[i]);
        }

        for (size_t i = 0; i < strip.size(); ++i)
            for (size_t j = i + 1; j < strip.size() && (strip[j].y - strip[i].y) < std::sqrt(d2); ++j)
                d2 = std::min(d2, dist2(strip[i], strip[j]));

        return d2;
    };

    double bestSq = rec(rec, 0, n);
    return std::sqrt(bestSq);
}
