#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <algorithm>
#include <omp.h>

#if !defined(M_PI)
#  define M_PI 3.14159265358979323846
#endif

/* In‑place, iterative FFT – Cooley‑Tukey radix‑2, with pre‑computed twiddle factors.
   The function works for any power‑of‑two length.
   Multithreaded: outer merge stages are parallelized with OpenMP.
*/
static void fft_impl(std::vector<std::complex<double>>& v) {
    const std::size_t N = v.size();
    if (N <= 1) return;
    const std::size_t logN = 64 - __builtin_clzll(N);
    // bit‑reversal permutation
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = ((i & 0x5555555555555555ULL) << 1) |
                        ((i & 0xAAAAAAAAAAAAAAAALL) >> 1);
        j = ((j & 0x3333333333333333ULL) << 2) |
            ((j & 0xCCCCCCCCCCCCCCCCULL) >> 2);
        j = ((j & 0x0F0F0F0F0F0F0F0FULL) << 4) |
            ((j & 0xF0F0F0F0F0F0F0F0ULL) >> 4);
        j = ((j & 0x00FF00FF00FF00FFULL) << 8) |
            ((j & 0xFF00FF00FF00FF00ULL) >> 8);
        j = ((j & 0x0000FFFF0000FFFFULL) << 16) |
            ((j & 0xFFFF0000FFFF0000ULL) >> 16);
        j >>= (64 - logN);
        if (j > i) std::swap(v[i], v[j]);
    }

    // pre‑compute all required twiddle factors
    std::vector<std::complex<double>> twiddles(N / 2);
    const double ang = -2.0 * M_PI / N;
    for (std::size_t k = 0; k < N / 2; ++k)
        twiddles[k] = std::exp(std::complex<double>(0, ang * k));

    // iterative stages
    for (std::size_t s = 1, m = 2; s <= logN; ++s, m <<= 1) {
        const std::size_t half = m >> 1;
        // parallel over each even block
#pragma omp parallel for schedule(static)
        for (std::size_t block = 0; block < N; block += m) {
            for (std::size_t j = 0; j < half; ++j) {
                const std::size_t idx = block + j;
                const std::size_t match = idx + half;
                const std::complex<double> t = twiddles[(j * N) / m] * v[match];
                v[match] = v[idx] - t;
                v[idx] += t;
            }
        }
    }
}

inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<std::complex<double>>& output)
{
    output = x;            // copy
    fft_impl(output);      // inplace FFT
}
