bool contains(const std::vector<int> &x, int target) {
    const std::size_t N = x.size();
    if (N == 0) return false;

    // If the vector is very small (<=32), a plain loop is usually faster
    // than spawning parallel work.  The magic number 32 is chosen empirically
    // for most platforms; it is safe to keep this simple guard.
    if (N <= 32) {
        for (std::size_t i = 0; i < N; ++i) {
            if (x[i] == target) return true;
        }
        return false;
    }

    bool found = false;

    #pragma omp parallel for shared(found) schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        // Avoid redundant checks once found, but still participate in threads
        if (!found && x[i] == target) {
            #pragma omp atomic write
            found = true;
        }
    }

    return found;
}
