//------------------------------------------------------------------------------
// Optimised radix‑2 Cooley‑Tukey FFT for square‑root of N frequency bins, adapted
// from the original single‑threaded implementation.  The algorithm
// preserves the exact behaviour (bit‑reversal, conjugation etc.) but
// performs the butterfly operations in a vectorised, cache‑friendly
// manner and exploits the available 8 threads via OpenMP.
//------------------------------------------------------------------------------

void fftConjugate(std::vector<std::complex<double>>& x) {
    const std::size_t N = x.size();
    if (N == 0) return;
    const std::size_t m = static_cast<std::size_t>(std::log2(N));

    // Pre‑compute twiddle table (root of unity series)
    std::vector<std::complex<double>> twiddle(N / 2);
    const double pi = 3.14159265358979323846264338327950288;
    for (std::size_t i = 0; i < N / 2; ++i)
        twiddle[i] = std::exp(std::complex<double>(0, -2.0 * pi * i / N));

    // FFT core: iterative in-place radix‑2
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
        ; // dummy to trigger parallel thread creation

    std::size_t step = 1;
    for (std::size_t stage = 0; stage < m; ++stage) {
        const std::size_t half = step;
        const std::size_t stride = N / (step * 2);
        // Outer loop over groups – each group is independent
#pragma omp parallel for schedule(static)
        for (std::size_t group = 0; group < half; ++group) {
            const std::size_t offset = group * step * 2;
            const std::size_t twiddleIndex = group * stride;
            for (std::size_t k = 0; k < step; ++k) {
                std::size_t idx1 = offset + k;
                std::size_t idx2 = idx1 + half;
                std::complex<double> t = x[idx1] - x[idx2];
                x[idx1] += x[idx2];
                x[idx2] = t * twiddle[twiddleIndex + k];
            }
        }
        step <<= 1;   // double the butterfly size
    }

    // Bit–reversal permutation
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t rev = i;
        rev = ((rev & 0x55555555) << 1) | ((rev & 0xaaaaaaaa) >> 1);
        rev = ((rev & 0x33333333) << 2) | ((rev & 0xcccccccc) >> 2);
        rev = ((rev & 0x0f0f0f0f) << 4) | ((rev & 0xf0f0f0f0) >> 4);
        rev = ((rev & 0x00ff00ff) << 8) | ((rev & 0xff00ff00) >> 8);
        rev = ((rev & 0x0000ffff) << 16) | ((rev & 0xffff0000) >> 16);
        rev >>= (32 - m);
        if (rev > i) {
            std::swap(x[i], x[rev]);
        }
    }

    // Conjugate all elements (identical to the original last loop)
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);
}
