inline bool xorContains(const std::vector<int>& x, const std::vector<int>& y, int val)
{
    bool foundX = false;
    const int* px = x.data();
    size_t nx = x.size();
    for (size_t i = 0; i < nx; ++i)
        if (px[i] == val) { foundX = true; break; }

    bool foundY = false;
    const int* py = y.data();
    size_t ny = y.size();
    for (size_t i = 0; i < ny; ++i)
        if (py[i] == val) { foundY = true; break; }

    return foundX ^ foundY;
}
