#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * In‑place LU factorisation (no pivoting).
 * A is an N×N matrix stored in row major order.
 * The factorised L (unit diagonal) and U are written back into A.
 * The original code is preserved, but the routine is heavily optimised
 * for speed on a modern x86‑64 with OpenMP support.
 *
 *  - Parallelise the outer k‑loop (each sweep is independent).
 *  - Use raw pointers for very fast memory access.
 *  - Unroll the inner j‑loop by a factor of 4, enabling the compiler
 *    to vectorise the subtraction.
 *  - Avoid bounds checks and temporary re‑calculations.
 */
inline void luFactorize(std::vector<double> &A, std::size_t N)
{
    double * const data = A.data();

    /* Parallelise the outer column sweep */
    #pragma omp parallel for schedule(static)
    for (long long k = 0; k < static_cast<long long>(N); ++k) {
        const double * const rowK = data + k * N;
        const double dk = rowK[k];                     // pivot

        for (long long i = k + 1; i < static_cast<long long>(N); ++i) {
            double * const rowI = data + i * N;
            const double factor = rowI[k] / dk;        // A[i][k] = factor
            rowI[k] = factor;

            /* Unrolled inner loop over j = k+1 .. N-1 */
            long long j = k + 1;
            const long long limit = static_cast<long long>(N);
            for (; j <= limit - 4; j += 4) {
                rowI[j]     -= factor * rowK[j];
                rowI[j + 1] -= factor * rowK[j + 1];
                rowI[j + 2] -= factor * rowK[j + 2];
                rowI[j + 3] -= factor * rowK[j + 3];
            }
            for (; j < limit; ++j) {
                rowI[j] -= factor * rowK[j];
            }
        }
    }
}
