#include <omp.h>

/* Multiply the matrix A by the vector x. Store the results in the vector y.
   A is an MxN matrix stored in row-major, x has N elements, and y has M elements.
   Example:
   input: A=[[1, -1, 2], [0, -3, 1]] x=[2, 1, 0]
   output: y=[1, -3]
*/
void gemv(std::vector<double> const& A,
          std::vector<double> const& x,
          std::vector<double> &y,
          size_t M,
          size_t N)
{
    // Choose an appropriate block size for matrix‑vector multiplication.
    // The block width (in columns) should be a multiple of the vector L1 cache
    // size - typical values are 128, 256, or 512 bytes (i.e. 16, 32, or 64 doubles).
    constexpr size_t BLOCK_COLS = 64;          // 512 bytes per block
    constexpr size_t BLOCK_ROWS = 256;        // 2 kB per block (fits in L2)

    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < M; i++) {
        double row_sum = 0.0;
        size_t j = 0;
        // Process full column blocks
        for (; j + BLOCK_COLS <= N; j += BLOCK_COLS) {
            size_t end = j + BLOCK_COLS;
            // Unroll the inner loop for better vectorization
            for (size_t jb = j; jb < end; jb += 4) {
                double a0 = A[i * N + jb];
                double a1 = A[i * N + jb + 1];
                double a2 = A[i * N + jb + 2];
                double a3 = A[i * N + jb + 3];
                double x0 = x[jb];
                double x1 = x[jb + 1];
                double x2 = x[jb + 2];
                double x3 = x[jb + 3];
                row_sum += a0 * x0 + a1 * x1 + a2 * x2 + a3 * x3;
            }
        }
        // Handle remaining columns
        for (; j < N; ++j) {
            row_sum += A[i * N + j] * x[j];
        }
        y[i] = row_sum;
    }
}
