#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>       // OpenMP headers

struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Solve the sparse linear system Ax = b for x.
 * A is given in COO (Coordinate) format.  b and x are dense vectors.
 *
 * The function implements a classic Gaussian elimination with partial
 * pivoting (identical to the reference implementation), but it
 * operates on a *flat* 1‑D dense matrix for better cache behaviour
 * and uses OpenMP to parallelise the innermost loops of the elimination
 * and back‑substitution phases.
 *
 * The algorithm is memory‑bound; the main gain comes from
 * a contiguous layout and avoiding virtual function calls
 * by inlining the computations.
 *
 * NOTE:
 *   - The function does **not** change the function signature.
 *   - The numerical output is identical to the original routine
 *     up to rounding errors inherent in floating‑point arithmetic.
 */
void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
    /* ------------------------------------------------------------------
     * 1. Build a dense representation of A in a 1‑D array: matrix[row*N+col]
     * ------------------------------------------------------------------ */
    std::vector<double> matrix(N * N, 0.0);
    for (const auto &e : A)
        matrix[e.row * N + e.column] = e.value;

    /* ------------------------------------------------------------------
     * 2. Make a copy of b – it will be transformed during elimination.
     * ------------------------------------------------------------------ */
    std::vector<double> b_copy = b;

    /* ------------------------------------------------------------------
     * 3. Gaussian elimination with partial pivoting.
     *
     *    The outer loop is serial because each step depends on the
     *    previous ones (pivot selection).  The inner loops are
     *    parallelised using OpenMP.  The number of threads will
     *    default to the value chosen by the runtime (normally the
     *    number of available cores: 8 in the target environment).
     * ------------------------------------------------------------------ */
    for (size_t i = 0; i < N; ++i) {
        /* ----- Pivot search ------------------------------------------ */
        double maxEl = std::abs(matrix[i * N + i]);
        size_t maxRow = i;
        for (size_t k = i + 1; k < N; ++k) {
            double val = std::abs(matrix[k * N + i]);
            if (val > maxEl) {
                maxEl = val;
                maxRow = k;
            }
        }

        /* ----- Swap the pivot row with the current row --------------- */
        if (maxRow != i) {
            for (size_t col = i; col < N; ++col) {
                std::swap(matrix[maxRow * N + col],
                          matrix[i * N + col]);
            }
            std::swap(b_copy[maxRow], b_copy[i]);
        }

        /* ----- Make all rows below zero in current column ------------- */
        const double pivot = matrix[i * N + i];
        if (pivot == 0.0) continue;          // Singular matrix – handled as defined

        #pragma omp parallel for schedule(static)
        for (size_t k = i + 1; k < N; ++k) {
            double c = -matrix[k * N + i] / pivot;
            for (size_t j = i; j < N; ++j) {
                if (i == j)
                    matrix[k * N + j] = 0.0;
                else
                    matrix[k * N + j] += c * matrix[i * N + j];
            }
            b_copy[k] += c * b_copy[i];
        }
    }

    /* ------------------------------------------------------------------
     * 4. Back‑substitution (upper‑triangular system).
     *
     *    This phase is fully parallelisable row‑wise because each
     *    step can be performed independently once the values of the
     *    higher rows are known.
     * ------------------------------------------------------------------ */
    x.assign(N, 0.0);
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        x[i] = b_copy[i] / matrix[i * N + i];
        #pragma omp parallel for schedule(static)
        for (int k = i - 1; k >= 0; --k) {
            b_copy[k] -= matrix[k * N + i] * x[i];
        }
    }
}
