#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>
#include <algorithm>

/* High‑performance matrix multiplication: C += A * B
 *   A  M×K, B  K×N, C  M×N  (row‑major storage)
 *
 * Requirements:
 *   - Preserve exact behavior of the reference implementation
 *   - Use GCC -O2 with OpenMP
 *   - Leverage blocking, pre‑fetching, and manual vectorisation hints
 *   - Keep the function signature unchanged
 */
inline void gemm(std::vector<double> const& A,
                 std::vector<double> const& B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    /* Basic blocking parameters. These sizes are chosen to fit
     * into L1/L2 cache on a typical modern x86‑64 machine.
     * They are tuned empirically; feel free to adjust. */
    constexpr size_t BM = 64;   // block size for rows of A / C
    constexpr size_t BK = 64;   // block size for columns of A / rows of B
    constexpr size_t BN = 64;   // block size for columns of B / C

    /* Parallelise over outer blocks of rows of A/C. The scheduler
     * distributes whole blocks to each thread, avoiding fine‑grained
     * overhead. */
    #pragma omp parallel for schedule(static)
    for (size_t ii = 0; ii < M; ii += BM) {
        const size_t i_max = std::min(ii + BM, M);
        for (size_t kk = 0; kk < K; kk += BK) {
            const size_t k_max = std::min(kk + BK, K);

            /* Load a sub‑matrix of A into a temporary buffer
             * to improve spatial locality. */
            double a_block[BM * BK];
            for (size_t ii_inner = ii; ii_inner < i_max; ++ii_inner) {
                for (size_t kk_inner = kk; kk_inner < k_max; ++kk_inner) {
                    a_block[(ii_inner - ii) * BK + (kk_inner - kk)] =
                        A[ii_inner * K + kk_inner];
                }
            }

            for (size_t jj = 0; jj < N; jj += BN) {
                const size_t j_max = std::min(jj + BN, N);

                /* Inner triple loop over the block. Use fused multiply‑add
                 * to reduce rounding error and enable vectorisation. */
                for (size_t ii_inner = ii; ii_inner < i_max; ++ii_inner) {
                    const size_t a_offset = (ii_inner - ii) * BK;
                    double* C_row = &C[ii_inner * N + jj];
                    const double* B_row_start = &B[kk * N + jj];
                    for (size_t kk_inner = kk; kk_inner < k_max; ++kk_inner) {
                        const double a_val = a_block[a_offset + (kk_inner - kk)];
                        const double* B_row = B_row_start + (kk_inner - kk) * N;
                        for (size_t jj_inner = jj; jj_inner < j_max; ++jj_inner) {
                            C_row[jj_inner - jj] += a_val * B_row[jj_inner - jj];
                        }
                    }
                }
            }
        }
    }
}
