```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   Example:

   input: A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
*/
void solveLinearSystem(std::vector<double> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       std::size_t N)
{
    // Work on copies so that the original data are untouched.
    std::vector<double> A_copy = A;
    std::vector<double> b_copy = b;

    // Forward elimination
    for (std::size_t i = 0; i < N - 1; ++i)
    {
        const double pivot = A_copy[i * N + i];
        if (pivot == 0.0)                 // singular system – abort
            return;

        // Parallel elimination of rows below the pivot row.
        // Each iteration of the outer loop is strictly consecutive,
        // but the inner row updates are independent.
        #pragma omp parallel for schedule(static)
        for (std::size_t j = i + 1; j < N; ++j)
        {
            const double factor = A_copy[j * N + i] / pivot;
            double *row_j = A_copy.data() + j * N;
            const double *row_i = A_copy.data() + i * N;

            // Unroll inner loop for the remaining columns.
            std::size_t k = i;
            for (; k + 3 < N; k += 4)
            {
                row_j[k  ] -= factor * row_i[k  ];
                row_j[k+1] -= factor * row_i[k+1];
                row_j[k+2] -= factor * row_i[k+2];
                row_j[k+3] -= factor * row_i[k+3];
            }
            for (; k < N; ++k)
                row_j[k] -= factor * row_i[k];

            // Update the RHS
            b_copy[j] -= factor * b_copy[i];
        }
    }

    // Back substitution (sequential – minimal overhead)
    for (std::ptrdiff_t i = static_cast<std::ptrdiff_t>(N) - 1; i >= 0; --i)
    {
        double sum = 0.0;
        const double *row_i = A_copy.data() + i * N;
        for (std::size_t j = i + 1; j < N; ++j)
            sum += row_i[j] * x[j];

        x[i] = (b_copy[i] - sum) / row_i[i];
    }
}
