#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

/*
 * Sorts in place `x` by the magnitude (|z|) of its complex elements.
 *
 * The implementation uses a parallel quick‑sort routine based on OpenMP
 * tasks.  For each recursion level we create at most one OpenMP task
 * (the left half), while the right half is processed by the calling thread.
 * The threshold for switching to std::sort is tuned for small buckets.
 *
 * This preserves the behaviour of the original implementation (exact
 * ordering for equal magnitudes) and takes advantage of all 8 hardware
 * threads on the target platform.
 */
inline double magnitude_squared(const std::complex<double>& z) noexcept {
    return std::norm(z);            // |z|² without a costly sqrt
}

inline bool cmp_by_mag(const std::complex<double>& a,
                       const std::complex<double>& b) noexcept {
    return magnitude_squared(a) < magnitude_squared(b);
}

constexpr std::size_t PARALLEL_THRESHOLD = 1 << 12;   // 4096

static void quicksort_parallel(std::vector<std::complex<double>>& v,
                               std::size_t left,
                               std::size_t right)
{
    if (right <= left + PARALLEL_THRESHOLD) {
        std::sort(v.begin() + left, v.begin() + right + 1, cmp_by_mag);
        return;
    }

    // Hoare partition
    std::size_t i = left, j = right;
    const auto& pivot = v[left + (right - left) / 2];

    while (i <= j) {
        while (cmp_by_mag(v[i], pivot)) ++i;
        while (cmp_by_mag(pivot, v[j])) --j;
        if (i <= j) {
            std::swap(v[i], v[j]);
            ++i;
            if (j-- == 0) break; // avoid underflow
        }
    }

    // Recurse on the two halves.  Launch the left half as an OpenMP task.
    if (left < j)
        #pragma omp task firstprivate(left, j, v)
        quicksort_parallel(v, left, j);

    if (i < right)
        quicksort_parallel(v, i, right);
}

void sortComplexByMagnitude(std::vector<std::complex<double>>& x)
{
    if (x.empty()) return;

    #pragma omp parallel
    {
        #pragma omp single nowait
        quicksort_parallel(x, 0, x.size() - 1);
    }
}
