#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/// Optimised Game of Life step.
/// `input`  – current state (NxN, row‑major).
/// `output` – buffer to receive the next state (NxN).
/// `N`      – grid dimension.
///
/// The algorithm pads the input with a zero border to avoid boundary
/// checks, then uses an 8‑element neighbour sum that is completely
/// branch‑free inside the inner loop.  OpenMP parallelisation is
/// applied to the outermost loop for maximum cache locality.
///
/// The functional semantics are identical to the reference implementation.
inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int>& output,
                       size_t N)
{
    // Pad with a 1‑cell border: (N+2) × (N+2)
    const size_t padded = N + 2;
    std::vector<int> pad((padded) * (padded), 0);

    // Copy input into the centre of the padded array
    const int* in = input.data();
    int* p = pad.data() + padded + 1;          // offset to row 1, col 1
    for (size_t i = 0; i < N; ++i, p += padded)
        std::copy(in + i * N, in + i * N + N, p);

    // Pre‑compute row stride for quick pointer jumps
    const int stride = static_cast<int>(padded);

    // Local pointers to input and output data
    const int* const padptr   = pad.data();
    int* const outptr          = output.data();

    // Offsets for the 8 neighbours relative to the current cell
    constexpr int offs[8] = {
        -stride - 1, -stride, -stride + 1,
        -1,         +1,
        +stride - 1, +stride, +stride + 1
    };

    // Parallelise the outer loop (row index).
    #pragma omp parallel for schedule(static)
    for (size_t i = 1; i <= N; ++i) {          // 1‑based inside padded array
        const int* const row = padptr + i * stride + 1;
        int* outRow = outptr + (i - 1) * N;   // back to original grid
        for (size_t j = 1; j <= N; ++j) {
            int sum = 0;
            const int* neighbour = row + j - 1; // point to current cell

            // Accumulate live neighbours
            sum += neighbour[ offs[0] ];
            sum += neighbour[ offs[1] ];
            sum += neighbour[ offs[2] ];
            sum += neighbour[ offs[3] ];
            sum += neighbour[ offs[4] ];
            sum += neighbour[ offs[5] ];
            sum += neighbour[ offs[6] ];
            sum += neighbour[ offs[7] ];

            // Apply Game of Life rules
            if (*neighbour) {                 // currently alive
                outRow[j - 1] = (sum == 2 || sum == 3) ? 1 : 0;
            } else {                           // currently dead
                outRow[j - 1] = (sum == 3) ? 1 : 0;
            }
        }
    }
}
