void reversePrefixSum(std::vector<int> const& x, std::vector<int> &output)
{
    const std::size_t N = x.size();
    if (N == 0) { output.clear(); return; }

    output.resize(N);

    const int max_threads = omp_get_max_threads();
    const std::size_t num_threads = N < static_cast<std::size_t>(max_threads) ? N : static_cast<std::size_t>(max_threads);
    const std::size_t chunk = (N + num_threads - 1) / num_threads; // round‑up

    std::vector<int> block_sums(num_threads, 0);

    /* Pass 1 – compute the sum of each block of the reversed vector */
    #pragma omp parallel for schedule(static, chunk)
    for (std::size_t tid = 0; tid < num_threads; ++tid) {
        std::size_t start = tid * chunk;
        std::size_t end   = start + chunk;
        if (end > N) end = N;

        int sum = 0;
        // iterate over reversed indices in this block
        for (std::size_t idx = start; idx < end; ++idx)
            sum += x[N - 1 - idx];
        block_sums[tid] = sum;
    }

    /* Pass 2 – prefix sums of block sums (sequential, size ≤ 8) */
    std::size_t block_prefix = 0;
    for (std::size_t tid = 0; tid < num_threads; ++tid) {
        int prev = block_sums[tid];
        block_sums[tid] = static_cast<int>(block_prefix);
        block_prefix += prev;
    }

    /* Pass 3 – compute inclusive scan within each block and write to output */
    #pragma omp parallel for schedule(static, chunk)
    for (std::size_t tid = 0; tid < num_threads; ++tid) {
        std::size_t start = tid * chunk;
        std::size_t end   = start + chunk;
        if (end > N) end = N;

        int running = 0;
        const int offset = block_sums[tid];
        for (std::size_t idx = start; idx < end; ++idx) {
            running += x[N - 1 - idx];
            const int rev_sum = running + offset;
            output[N - 1 - idx] = rev_sum;
        }
    }
}
